/* General Styling */
:root {
    --primary-font: 'Playfair Display', serif;
    --secondary-font: 'Open Sans', sans-serif;
    --dark-bg: #1a1a1a;
    --light-text: #f5f5f5;
    --accent-color: #d4af37; /* Gold */
    --secondary-bg: #2a2a2a;
    --border-color: #444;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: var(--secondary-font);
    line-height: 1.6;
    color: var(--light-text);
    background-color: var(--dark-bg);
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

h2 {
    font-family: var(--primary-font);
    font-size: 3em;
    text-align: center;
    margin-bottom: 60px;
    color: var(--accent-color);
    position: relative;
}

h2::after {
    content: '';
    position: absolute;
    left: 50%;
    bottom: -15px;
    transform: translateX(-50%);
    width: 80px;
    height: 3px;
    background-color: var(--accent-color);
}

.btn {
    display: inline-block;
    background: var(--accent-color);
    color: var(--dark-bg);
    padding: 12px 30px;
    text-decoration: none;
    border-radius: 5px;
    transition: background 0.3s ease;
    font-weight: 600;
    letter-spacing: 0.5px;
}

.btn:hover {
    background: #c29d2b;
}

.btn-secondary {
    background: transparent;
    border: 2px solid var(--accent-color);
    color: var(--accent-color);
}

.btn-secondary:hover {
    background: var(--accent-color);
    color: var(--dark-bg);
}

/* Header & Hero Section */
.hero {
    background: linear-gradient(rgba(0,0,0,0.6), rgba(0,0,0,0.6)), url('https://images.unsplash.com/photo-1511920170033-f8396924c348?q=80&w=2940&auto=format&fit=crop&ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D') no-repeat center center/cover;
    height: 100vh;
    display: flex;
    align-items: center;
    text-align: center;
    position: relative;
}

nav {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 0;
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    background-color: rgba(26, 26, 26, 0.8);
    z-index: 1000;
}

nav .logo {
    font-family: var(--primary-font);
    font-size: 1.8em;
    color: var(--accent-color);
    padding-left: 20px;
}

nav ul {
    display: flex;
    list-style: none;
    padding-right: 20px;
}

nav ul li {
    margin-left: 30px;
}

nav ul li a {
    color: var(--light-text);
    text-decoration: none;
    font-weight: 600;
    transition: color 0.3s ease;
    position: relative;
}

nav ul li a::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: -5px;
    width: 0;
    height: 2px;
    background-color: var(--accent-color);
    transition: width 0.3s ease;
}

nav ul li a:hover::after {
    width: 100%;
}

.hero-content {
    max-width: 800px;
    margin: 0 auto;
}

.hero-content h1 {
    font-family: var(--primary-font);
    font-size: 4.5em;
    margin-bottom: 20px;
    color: var(--light-text);
    text-shadow: 2px 2px 5px rgba(0,0,0,0.7);
}

.hero-content p {
    font-size: 1.4em;
    margin-bottom: 40px;
    color: var(--light-text);
    opacity: 0.9;
}

/* Sections */
section {
    padding: 100px 0;
}

.about-us, .menu-section, .gallery-section, .contact-section {
    background-color: var(--secondary-bg);
    margin-bottom: 50px;
    border-radius: 10px;
    box-shadow: 0 5px 15px rgba(0,0,0,0.3);
}

.about-us .container, .contact-section .container {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 40px;
}

.about-content {
    flex: 1;
}

.about-content h2 {
    text-align: left;
    margin-bottom: 30px;
}

.about-content h2::after {
    left: 0;
    transform: none;
}

.about-content p {
    font-size: 1.1em;
    margin-bottom: 20px;
    color: #ccc;
}

.about-image {
    flex: 1;
    text-align: right;
}

.about-image img {
    max-width: 100%;
    border-radius: 8px;
    box-shadow: 0 5px 15px rgba(0,0,0,0.5);
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 40px;
    margin-top: 50px;
}

.menu-item {
    background-color: var(--dark-bg);
    padding: 30px;
    border-radius: 8px;
    box-shadow: 0 4px 10px rgba(0,0,0,0.2);
    text-align: center;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.menu-item:hover {
    transform: translateY(-10px);
    box-shadow: 0 8px 20px rgba(0,0,0,0.4);
}

.menu-item h3 {
    font-family: var(--primary-font);
    font-size: 1.8em;
    color: var(--accent-color);
    margin-bottom: 25px;
    position: relative;
}

.menu-item h3::after {
    content: '';
    position: absolute;
    left: 50%;
    bottom: -10px;
    transform: translateX(-50%);
    width: 50px;
    height: 2px;
    background-color: var(--light-text);
}

.menu-item ul {
    list-style: none;
    padding: 0;
}

.menu-item ul li {
    font-size: 1.1em;
    padding: 10px 0;
    border-bottom: 1px dashed var(--border-color);
    color: #ccc;
}

.menu-item ul li:last-child {
    border-bottom: none;
}

.menu-section .btn {
    margin-top: 60px;
    text-align: center;
    width: fit-content;
    margin-left: auto;
    margin-right: auto;
}

.gallery-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 20px;
}

.gallery-grid img {
    width: 100%;
    height: 250px;
    object-fit: cover;
    border-radius: 8px;
    box-shadow: 0 4px 10px rgba(0,0,0,0.3);
    transition: transform 0.3s ease;
}

.gallery-grid img:hover {
    transform: scale(1.05);
}

.contact-section p {
    text-align: center;
    font-size: 1.2em;
    margin-bottom: 40px;
    color: #ccc;
}

.contact-info {
    display: flex;
    justify-content: space-around;
    text-align: center;
    gap: 30px;
    margin-bottom: 50px;
    flex-wrap: wrap;
}

.contact-info div {
    background-color: var(--dark-bg);
    padding: 30px;
    border-radius: 8px;
    flex: 1;
    min-width: 250px;
    box-shadow: 0 4px 10px rgba(0,0,0,0.2);
}

.contact-info h3 {
    font-family: var(--primary-font);
    color: var(--accent-color);
    margin-bottom: 15px;
}

.contact-info p {
    font-size: 1.1em;
    margin-bottom: 10px;
    color: #ccc;
}

.contact-section .btn {
    display: block;
    width: fit-content;
    margin: 0 auto;
}

/* Footer */
footer {
    background-color: var(--dark-bg);
    color: var(--light-text);
    text-align: center;
    padding: 30px 0;
    border-top: 1px solid var(--border-color);
}

footer p {
    font-size: 0.9em;
    color: #aaa;
}

/* Responsive Design */
@media (max-width: 768px) {
    nav {
        flex-direction: column;
        align-items: center;
    }

    nav .logo {
        padding-left: 0;
        margin-bottom: 15px;
    }

    nav ul {
        padding-right: 0;
        flex-wrap: wrap;
        justify-content: center;
    }

    nav ul li {
        margin: 0 15px 10px 15px;
    }

    .hero-content h1 {
        font-size: 3em;
    }

    .hero-content p {
        font-size: 1.1em;
    }

    .about-us .container {
        flex-direction: column;
        text-align: center;
    }

    .about-content h2 {
        text-align: center;
    }

    .about-content h2::after {
        left: 50%;
        transform: translateX(-50%);
    }

    .about-image {
        text-align: center;
        margin-top: 30px;
    }

    .contact-info {
        flex-direction: column;
        align-items: center;
    }

    .contact-info div {
        min-width: unset;
        width: 100%;
    }

    h2 {
        font-size: 2.5em;
    }
}

